import { useState } from "react";

const MEMBROS = ["Lucas", "Sheila", "Ana", "Pedro", "Você"];

function PageNovaTarefa({ projetos, setProjetos, setPage, showToast }) {
  const [titulo, setTitulo] = useState("");
  const [descricao, setDescricao] = useState("");
  const [responsavel, setResponsavel] = useState("");
  const [prazo, setPrazo] = useState("");
  const [status, setStatus] = useState("Pendente");
  const [projetoNome, setProjetoNome] = useState("");
  const [sugestoes, setSugestoes] = useState([]);

  function handleProjetoInput(valor) {
    setProjetoNome(valor);
    if (valor.trim().length === 0) { setSugestoes([]); return; }
    const filtradas = projetos.filter(p => p.nome.toLowerCase().includes(valor.toLowerCase()));
    setSugestoes(filtradas);
  }

  function selecionarSugestao(nome) {
    setProjetoNome(nome);
    setSugestoes([]);
  }

  function getProjetoId() {
    const encontrado = projetos.find(p => p.nome.toLowerCase() === projetoNome.toLowerCase());
    return encontrado?.id || null;
  }

  function handleSubmit() {
    const projetoId = getProjetoId();
    if (!titulo.trim() || !responsavel || !prazo || !projetoId) return;
    const newTarefa = { id: Date.now(), titulo: titulo.trim(), descricao: descricao.trim(), responsavel, prazo, status };
    setProjetos(prev => prev.map(p => p.id === projetoId ? { ...p, tarefas: [...p.tarefas, newTarefa] } : p));
    showToast("✓ Tarefa criada com sucesso!");
    setPage("dashboard");
  }

  const projetoValido = !!getProjetoId();

  return (
    <div className="slide-in">
      <div className="card form-card">
        <div className="form-title">Adicionar Nova Tarefa</div>

        {/* PROJETO */}
        <div className="form-group" style={{ position: "relative" }}>
          <label className="form-label"></label>
          <input
            className="form-input"
            value={projetoNome}
            onChange={e => handleProjetoInput(e.target.value)}
            placeholder="Digite o nome do projeto..."
            autoComplete="off"
          />
          {projetoNome.length > 0 && (
            <span style={{ fontSize: 12, marginTop: 4, display: "block", color: projetoValido ? "var(--success)" : "var(--danger)" }}>
              {projetoValido ? "✓ Projeto encontrado" : "✗ Projeto não encontrado"}
            </span>
          )}
          {sugestoes.length > 0 && (
            <div style={{
              position: "absolute", top: "100%", left: 0, right: 0,
              background: "var(--surface2)", border: "1px solid var(--border2)",
              borderRadius: "var(--radius-sm)", zIndex: 10, overflow: "hidden", marginTop: 2,
            }}>
              {sugestoes.map(p => (
                <div
                  key={p.id}
                  onClick={() => selecionarSugestao(p.nome)}
                  style={{ padding: "10px 14px", fontSize: 14, cursor: "pointer", borderBottom: "1px solid var(--border)", transition: "background 0.15s" }}
                  onMouseEnter={e => e.currentTarget.style.background = "var(--surface3)"}
                  onMouseLeave={e => e.currentTarget.style.background = "transparent"}
                >
                  {p.nome}
                </div>
              ))}
            </div>
          )}
        </div>

        {/* TÍTULO */}
        <div className="form-group">
          <label className="form-label">Título da Tarefa</label>
          <input className="form-input" value={titulo} onChange={e => setTitulo(e.target.value)} placeholder="Ex: Implementar autenticação..." />
        </div>

        {/* DESCRIÇÃO */}
        <div className="form-group">
          <label className="form-label">Descrição</label>
          <input className="form-input" value={descricao} onChange={e => setDescricao(e.target.value)} placeholder="Descreva brevemente a tarefa..." />
        </div>

        {/* RESPONSÁVEL — select */}
        <div className="form-group">
          <label className="form-label">Responsável</label>
          <select className="form-input" value={responsavel} onChange={e => setResponsavel(e.target.value)}>
            <option value="">Selecione um membro...</option>
            {MEMBROS.map(m => <option key={m} value={m}>{m}</option>)}
          </select>
        </div>

        {/* PRAZO */}
        <div className="form-group">
          <label className="form-label">Prazo</label>
          <input className="form-input" type="date" value={prazo} onChange={e => setPrazo(e.target.value)} />
        </div>

        {/* STATUS */}
        <div className="form-group">
          <label className="form-label">Status Inicial</label>
          <select className="form-input" value={status} onChange={e => setStatus(e.target.value)}>
            <option>Pendente</option>
            <option>Em Andamento</option>
            <option>Concluído</option>
          </select>
        </div>

        <div className="row mt-16">
          <button className="btn btn-ghost" onClick={() => setPage("dashboard")}>Cancelar</button>
          <button className="btn btn-primary" onClick={handleSubmit} disabled={!titulo.trim() || !responsavel || !prazo || !projetoValido}>
            Salvar Tarefa
          </button>
        </div>
      </div>
    </div>
  );
}

export default PageNovaTarefa;
